class Solution:

def isValidSudoku(self, board: List[List[int]]) -> bool:
	for i in range(9):
		for j in range(9):
			if board[i][j] != 0:
				self.isValid(board[i][j], 0, 9, board[i][j])
				else:
				self.isValid(0, 0, 9, i, j)
				self.isValid(0, 0, 9, i, j)
				if not self.isValid(0, 0, 9, i, j):
					return False
		return True

def isValid(self, num, low, high, row, column):
	if num == 0:
		self.isValid(low, high, board[row][column])
	for i in range(9):
		if board[row][i] == num or board[i][column] == num:
			return False
	for r in range((row // 3) * 3, (row // 3 + 1) * 3):
		for c in range((column // 3) * 3, (column // 3 + 1) * 3):
			if board[r][c] == num:
				return False
	return True

