class Solution
{
public:
	bool isValidSudoku(vector<vector<int>>& board)
	{
		for (int i = 0; i < 9; i++)
		{
			for (int j = 0; j < 9; j++)
			{
				if (board[i][j] != 0)
				{
					isValid(board[i][j], i, j);
				}
				else
				{
					isValid(0, i, j);
					isValid(i, j);
				}
				if (!isValid(0, i, j))
				{
					return false;
				}
			}
		}
		return true;
	bool isValid(int num, int row, int column)
	{
		if (num == 0)
		{
			isValid(num, 0, 9, column);
		}
		for (int i = 0; i < 9; i++)
		{
			if (board[row][i] == num || board[i][column] == num)
			{
				return false;
			}
		}
		for (int r = (row / 3) * 3; r < (row / 3 + 1) * 3; r++)
		{
			for (int c = (column / 3) * 3; c < (column / 3 + 1) * 3; c++)
			{
				if (board[r][c] == num)
				{
					return false;
				}
			}
		}
		return true;
	}
};
